import { useState, useEffect, useCallback } from "react";
import axios from "axios";

const API_URL = "http://localhost:5000/api/features";

export function useFeatures() {
  const [features, setFeatures] = useState([]);

  // Fetch all features from backend
  useEffect(() => {
    axios.get(API_URL)
      .then(res => setFeatures(res.data))
      .catch(err => console.error("Failed to fetch features:", err));
  }, []);

  // Add feature
  const addFeature = useCallback(async (data) => {
    try {
      const res = await axios.post(API_URL, data);
      setFeatures(f => [...f, res.data]);
    } catch (err) {
      console.error("Failed to add feature:", err);
    }
  }, []);

  // Update feature
  const updateFeature = useCallback(async (id, data) => {
    try {
      const res = await axios.put(`${API_URL}/${id}`, data);
      setFeatures(f => f.map(feat => feat.id === id ? res.data : feat));
    } catch (err) {
      console.error("Failed to update feature:", err);
    }
  }, []);

  // Delete feature
  const deleteFeature = useCallback(async (id) => {
    try {
      await axios.delete(`${API_URL}/${id}`);
      setFeatures(f => f.filter(feat => feat.id !== id));
    } catch (err) {
      console.error("Failed to delete feature:", err);
    }
  }, []);

  // Update status
  const updateStatus = useCallback(async (id, status) => {
    try {
      const feature = features.find(f => f.id === id);
      if (!feature) return;
      const res = await axios.put(`${API_URL}/${id}`, { ...feature, status });
      setFeatures(f => f.map(feat => feat.id === id ? res.data : feat));
    } catch (err) {
      console.error("Failed to update status:", err);
    }
  }, [features]);

  return { features, addFeature, updateFeature, deleteFeature, updateStatus };
}
